#include <stdio.h>
void floodFill(int** image, int imageSize, int* imageColSize, int sr, int sc, int newColor){
   int oldColor = image[sr][sc];
   if(oldColor == newColor) return;
   dfs(image, imageSize, imageColSize, sr, sc, oldColor, newColor);
}
void dfs(int** image, int imageSize, int* imageColSize, int sr, int sc, int oldColor, int newColor){
   if(sr < 0 || sr >= imageSize || sc < 0 || sc >= imageColSize[sr]) return;
   if(image[sr][sc] != oldColor) return;
   image[sr][sc] = newColor;
   dfs(image, imageSize, imageColSize, sr-1, sc, oldColor, newColor);
   dfs(image, imageSize, imageColSize, sr+1, sc, oldColor, newColor);
   dfs(image, imageSize, imageColSize, sr, sc-1, oldColor, newColor);
   dfs(image, imageSize, imageColSize, sr, sc+1, oldColor, newColor);
}

code.C++:
#include <vector>
class Solution {
public:
   std::vector<std::vector<int>> floodFill(std::vector<std::vector<int>>& image, int sr, int sc, int newColor) {
      int oldColor = image[sr][sc];
      if(oldColor == newColor) return image;
      dfs(image, sr, sc, oldColor, newColor);
      return image;
   }
   void dfs(std::vector<std::vector<int>>& image, int sr, int sc, int oldColor, int newColor){
      if(sr < 0 || sr >= image.size() || sc < 0 || sc >= image[0].size()) return;
      if(image[sr][sc] != oldColor) return;
      image[sr][sc] = newColor;
      dfs(image, sr-1, sc, oldColor, newColor);
      dfs(image, sr+1, sc, oldColor, newColor);
      dfs(image, sr, sc-1, oldColor, newColor);
      dfs(image, sr, sc+1, oldColor, newColor);
   }
};

